import{_ as i,c as l,a0 as t,o as a}from"./chunks/framework.B6JXc2q-.js";const _=JSON.parse('{"title":"认证运行时恢复规范","description":"","frontmatter":{},"headers":[],"relativePath":"spec/auth_runtime_recovery.md","filePath":"spec/auth_runtime_recovery.md"}'),o={name:"spec/auth_runtime_recovery.md"};function r(d,e,c,n,u,s){return a(),l("div",null,e[0]||(e[0]=[t('<h1 id="认证运行时恢复规范" tabindex="-1">认证运行时恢复规范 <a class="header-anchor" href="#认证运行时恢复规范" aria-label="Permalink to &quot;认证运行时恢复规范&quot;">​</a></h1><blockquote><p>最后更新：2026-04-09</p></blockquote><h2 id="_1-文档定位" tabindex="-1">1. 文档定位 <a class="header-anchor" href="#_1-文档定位" aria-label="Permalink to &quot;1. 文档定位&quot;">​</a></h2><p>本文档描述 <strong>当前 auth runtime 恢复主线</strong> 的实现语义、阶段边界与验收口径。</p><p>本文档解决：</p><ul><li>当前 auth runtime 恢复主路径是什么</li><li><code>_try_login()</code> 在恢复链中的职责与阶段边界</li><li>哪些信号可以判断失败发生在 login-stage，哪些发生在 verify-stage</li><li>本轮已确认通过的是哪一层，不是哪一层</li></ul><p>本文档不解决：</p><ul><li>spec rebuild 全量验收</li><li>singleflight 的并发闭环是否已被线上充分证明</li><li>fallback path 的独立验收</li><li>auth / playback 交叉边界</li><li>极端网络扰动下的全部恢复行为</li></ul><hr><h2 id="_2-当前-auth-主线" tabindex="-1">2. 当前 auth 主线 <a class="header-anchor" href="#_2-当前-auth-主线" aria-label="Permalink to &quot;2. 当前 auth 主线&quot;">​</a></h2><p>当前真实主线已经不是“自动登录 fallback 被禁用，因此不再走服务端登录恢复”这一旧表述。</p><p>当前实现中，<strong><code>_try_login()</code> 是 auth runtime 恢复的核心路径之一</strong>。其主线语义为：</p><ol><li>从当前可用认证材料出发准备登录输入</li><li><strong>恢复登录前使用 fresh <code>ClientSession</code></strong>，避免复用旧 session 导致的 <code>login_result=false</code></li><li>调用 <code>MiAccount.login(&quot;micoapi&quot;)</code></li><li><strong>只有 login 成功后，才允许构建候选 runtime</strong></li><li><strong>只有候选 runtime 的 account / cookie ready 后，才允许进入 verify</strong></li><li>verify 成功后，才允许进行 runtime swap</li><li>verify 失败时，候选 runtime 必须被丢弃，<strong>不得污染旧 runtime</strong></li></ol><p>换句话说，当前主路径不再把失败笼统写成“runtime verify failed”或“自动登录 fallback 被禁用”，而是明确分成：</p><ul><li><strong>login-stage failure</strong></li><li><strong>verify-stage failure</strong></li></ul><hr><h2 id="_3-三层认证模型" tabindex="-1">3. 三层认证模型 <a class="header-anchor" href="#_3-三层认证模型" aria-label="Permalink to &quot;3. 三层认证模型&quot;">​</a></h2><ul><li>长期认证状态（持久化）：<code>passToken</code>、<code>psecurity</code>、<code>ssecurity</code>、<code>userId</code>、<code>cUserId</code>、<code>deviceId</code></li><li>短期会话状态（持久化）：<code>serviceToken</code>、<code>yetAnotherServiceToken</code></li><li>运行时状态（内存）：<code>MiAccount</code> seed、<code>mina_service</code>、<code>miio_service</code>、device map</li></ul><p>系统仍以 <code>auth.json</code> / <code>TokenStore</code> 为事实来源。</p><hr><h2 id="_4-try-login-主路径阶段定义" tabindex="-1">4. <code>_try_login()</code> 主路径阶段定义 <a class="header-anchor" href="#_4-try-login-主路径阶段定义" aria-label="Permalink to &quot;4. `_try_login()` 主路径阶段定义&quot;">​</a></h2><h3 id="_4-1-阶段顺序" tabindex="-1">4.1 阶段顺序 <a class="header-anchor" href="#_4-1-阶段顺序" aria-label="Permalink to &quot;4.1 阶段顺序&quot;">​</a></h3><p>当前 <code>_try_login()</code> 主路径按以下阶段理解：</p><ol><li><p><strong>token load</strong></p><ul><li>读取当前可用认证材料，准备登录输入</li></ul></li><li><p><strong>fresh session login</strong></p><ul><li>创建 fresh <code>ClientSession</code></li><li>创建新的 <code>MiAccount</code></li><li>调用 <code>MiAccount.login(&quot;micoapi&quot;)</code></li></ul></li><li><p><strong>candidate runtime readiness</strong></p><ul><li>仅在 login 成功后继续</li><li>检查候选 runtime 的 account/cookie 是否 ready</li></ul></li><li><p><strong>verify</strong></p><ul><li>仅在候选 runtime ready 后继续</li><li>调用 <code>device_list</code> 等方式验证 runtime 是否可用</li></ul></li><li><p><strong>runtime swap</strong></p><ul><li>仅在 verify 成功后允许</li><li>原子替换当前 runtime 引用</li></ul></li></ol><h3 id="_4-2-禁止跨阶段跳跃" tabindex="-1">4.2 禁止跨阶段跳跃 <a class="header-anchor" href="#_4-2-禁止跨阶段跳跃" aria-label="Permalink to &quot;4.2 禁止跨阶段跳跃&quot;">​</a></h3><ul><li><code>login_result=false</code> 时，不得继续进入 verify</li><li><code>candidate_runtime_account_ready=false</code> 时，不得继续进入 verify</li><li><code>candidate_runtime_cookie_ready=false</code> 时，不得继续进入 verify</li><li>verify 失败时，不得把候选 runtime swap 到当前运行态</li></ul><hr><h2 id="_5-当前关键观测字段" tabindex="-1">5. 当前关键观测字段 <a class="header-anchor" href="#_5-当前关键观测字段" aria-label="Permalink to &quot;5. 当前关键观测字段&quot;">​</a></h2><p>当前主路径的关键观测字段至少包括：</p><ul><li><code>login_result</code></li><li><code>token_changed_after_login</code></li><li><code>candidate_runtime_account_ready</code></li><li><code>candidate_runtime_cookie_ready</code></li><li><code>verify_attempted</code></li><li><code>verify_error_text</code></li><li><code>runtime_swap_attempted</code></li><li><code>runtime_swap_applied</code></li><li><code>recovery_failure_count</code></li></ul><p>这些字段的基本语义：</p><table tabindex="0"><thead><tr><th>字段</th><th>语义</th></tr></thead><tbody><tr><td><code>login_result</code></td><td><code>MiAccount.login(&quot;micoapi&quot;)</code> 是否成功</td></tr><tr><td><code>token_changed_after_login</code></td><td>login 后 token 快照是否变化</td></tr><tr><td><code>candidate_runtime_account_ready</code></td><td>候选 runtime 的 account 种子是否 ready</td></tr><tr><td><code>candidate_runtime_cookie_ready</code></td><td>候选 runtime 的 cookie / token 注入是否 ready</td></tr><tr><td><code>verify_attempted</code></td><td>本轮是否真正进入 verify</td></tr><tr><td><code>verify_error_text</code></td><td>verify 阶段错误文本</td></tr><tr><td><code>runtime_swap_attempted</code></td><td>是否尝试 swap 候选 runtime</td></tr><tr><td><code>runtime_swap_applied</code></td><td>是否最终把候选 runtime 应用到当前运行态</td></tr><tr><td><code>recovery_failure_count</code></td><td>恢复失败累计计数</td></tr></tbody></table><hr><h2 id="_6-login-stage-failure-与-verify-stage-failure-的区分" tabindex="-1">6. login-stage failure 与 verify-stage failure 的区分 <a class="header-anchor" href="#_6-login-stage-failure-与-verify-stage-failure-的区分" aria-label="Permalink to &quot;6. login-stage failure 与 verify-stage failure 的区分&quot;">​</a></h2><h3 id="_6-1-login-stage-failure" tabindex="-1">6.1 login-stage failure <a class="header-anchor" href="#_6-1-login-stage-failure" aria-label="Permalink to &quot;6.1 login-stage failure&quot;">​</a></h3><p>典型特征：</p><ul><li><code>login_result=false</code></li><li><code>verify_attempted=false</code></li><li><code>runtime_swap_attempted=false</code></li><li><code>runtime_swap_applied=false</code></li></ul><p>语义：</p><ul><li>失败发生在登录阶段</li><li>本轮不应继续进入 verify</li><li>不应把这类失败写成 verify 失败</li></ul><h3 id="_6-2-verify-stage-failure" tabindex="-1">6.2 verify-stage failure <a class="header-anchor" href="#_6-2-verify-stage-failure" aria-label="Permalink to &quot;6.2 verify-stage failure&quot;">​</a></h3><p>典型特征：</p><ul><li><code>login_result=true</code></li><li><code>candidate_runtime_account_ready=true</code></li><li><code>candidate_runtime_cookie_ready=true</code></li><li><code>verify_attempted=true</code></li><li><code>runtime_swap_applied=false</code></li></ul><p>语义：</p><ul><li>登录已成功，候选 runtime 已具备进入 verify 的前提</li><li>失败发生在 verify 阶段</li><li>旧 runtime 必须保持不被污染</li></ul><h3 id="_6-3-当前实现约束" tabindex="-1">6.3 当前实现约束 <a class="header-anchor" href="#_6-3-当前实现约束" aria-label="Permalink to &quot;6.3 当前实现约束&quot;">​</a></h3><ul><li><strong>login-stage failure 与 verify-stage failure 必须作为两种不同失败处理</strong></li><li>不允许再把二者混写成单一“自动恢复失败”</li></ul><hr><h2 id="_7-refresh-refresh-runtime-auto-runtime-reload-的关系" tabindex="-1">7. refresh / refresh_runtime / auto runtime reload 的关系 <a class="header-anchor" href="#_7-refresh-refresh-runtime-auto-runtime-reload-的关系" aria-label="Permalink to &quot;7. refresh / refresh_runtime / auto runtime reload 的关系&quot;">​</a></h2><ul><li><code>POST /api/auth/refresh</code></li><li><code>POST /api/auth/refresh_runtime</code></li></ul><p>这两个入口仍表示手动触发 runtime 恢复。</p><p>自动 runtime reload 仍来自：</p><ul><li><code>init_all_data()</code></li><li><code>keepalive_loop()</code></li></ul><p>但无论手动还是自动触发，<strong>都不应改变 <code>_try_login()</code> 主路径的阶段语义</strong>。触发方式与执行阶段需要分开描述。</p><hr><h2 id="_8-本轮已确认通过的范围" tabindex="-1">8. 本轮已确认通过的范围 <a class="header-anchor" href="#_8-本轮已确认通过的范围" aria-label="Permalink to &quot;8. 本轮已确认通过的范围&quot;">​</a></h2><p>本轮已有证据只能支持以下结论：</p><h3 id="_8-1-已确认通过" tabindex="-1">8.1 已确认通过 <a class="header-anchor" href="#_8-1-已确认通过" aria-label="Permalink to &quot;8.1 已确认通过&quot;">​</a></h3><p><strong>fresh session 修补后的 <code>_try_login()</code> 主路径稳定性</strong></p><p>在本轮 <strong>&gt;24h 观察窗口</strong> 内，已确认：</p><ul><li>未复发 <code>login_result=false</code> 异常</li><li><code>candidate_runtime_account_ready</code> / <code>runtime_swap_applied</code> 正常</li><li><code>recovery_failure_count</code> 未异常上涨</li><li><code>/api/auth/status</code> 与 debug 业务结论一致，均指向 healthy</li></ul><h3 id="_8-2-适用范围" tabindex="-1">8.2 适用范围 <a class="header-anchor" href="#_8-2-适用范围" aria-label="Permalink to &quot;8.2 适用范围&quot;">​</a></h3><p>以上结论只适用于：</p><ul><li>fresh session 修补后的 <code>_try_login()</code> 主路径</li><li>当前观察窗口内的主路径稳定性</li><li>login-stage / verify-stage 已可区分这一层</li></ul><h3 id="_8-3-不可外推范围" tabindex="-1">8.3 不可外推范围 <a class="header-anchor" href="#_8-3-不可外推范围" aria-label="Permalink to &quot;8.3 不可外推范围&quot;">​</a></h3><p>以上结论<strong>不等于</strong>：</p><ul><li>spec rebuild 全量通过</li><li>auto runtime reload 全量通过</li><li>singleflight 已完成实机闭环</li><li>fallback path 已独立验收通过</li><li>auth / playback 交叉边界已通过</li><li>极端网络扰动下恢复行为已通过</li></ul><hr><h2 id="_9-locked-策略" tabindex="-1">9. Locked 策略 <a class="header-anchor" href="#_9-locked-策略" aria-label="Permalink to &quot;9. Locked 策略&quot;">​</a></h2><p><code>auth locked</code> 仍是终态保护状态，只应在长期认证材料缺失或等价硬故障时触发。</p><p>以下情况不应直接进入 locked：</p><ul><li>短期会话失效</li><li>单次 login-stage failure</li><li>单次 verify-stage failure</li><li>fresh session 主路径中的一次恢复失败</li></ul><hr><h2 id="_10-可观测性" tabindex="-1">10. 可观测性 <a class="header-anchor" href="#_10-可观测性" aria-label="Permalink to &quot;10. 可观测性&quot;">​</a></h2><p>相关调试接口仍包括：</p><ul><li><code>GET /api/v1/debug/auth_state</code></li><li><code>GET /api/v1/debug/auth_recovery_state</code></li><li><code>GET /api/v1/debug/miaccount_login_trace</code></li><li><code>GET /api/v1/debug/auth_runtime_reload_state</code></li></ul><p>后续任何验收结论都应至少写清：</p><ul><li>本次通过的是哪一层</li><li>本次没有覆盖的不是哪一层</li><li>使用了哪些字段作为证据</li><li>观察窗口有多长</li></ul><hr><h2 id="_11-已知边界" tabindex="-1">11. 已知边界 <a class="header-anchor" href="#_11-已知边界" aria-label="Permalink to &quot;11. 已知边界&quot;">​</a></h2><ul><li>Xiaomi 云端风控仍不可消除</li><li>系统目标仍是“低频失败、可恢复、可观测、可预测”，不是零失败</li><li>当前主路径通过，不等于所有恢复分支通过</li><li>当前文档描述的是<strong>已收口到的新主线</strong>，不是 spec rebuild 全量结论</li></ul>',80)]))}const p=i(o,[["render",r]]);export{_ as __pageData,p as default};
